INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('Organisation de la paie et RH avec logiciel', 'Formation sur la conception et le pilotage de projets Big Data pour optimiser la stratégie et la prise de décision.', 5, 250000.00, 'entreprise', '2026-10-15', 30, '2026-01-14 12:37:32', '2026-02-18 23:44:04', NULL, E'--- OBJECTIFS ---\n• Comprendre les concepts clés du Big Data\n• Identifier les besoins et opportunités pour un projet Big Data\n• Concevoir et structurer un projet de manière efficace\n• Piloter les équipes et ressources pour garantir la réussite\n• Exploiter les données pour orienter la stratégie commerciale\n\n--- OBJECTIFS DÉTAILLÉS ---\nComprendre les concepts clés du Big Data, identifier les besoins et opportunités, concevoir et structurer un projet Big Data, piloter les équipes et ressources, et utiliser les données pour prendre des décisions stratégiques.\n\n--- PRÉREQUIS ---\nConnaissances de base en gestion de projet et en analyse de données. Une familiarité avec les outils numériques est recommandée.\n\n--- CONTENU ---\nModule 1 : Introduction au Big Data et enjeux stratégiques\nModule 2 : Identification des besoins et cadrage du projet\nModule 3 : Architecture et conception du projet Big Data\nModule 4 : Pilotage et gestion de projet Big Data\nModule 5 : Analyse des données et prise de décision\nModule 6 : Gouvernance, sécurité et éthique des données\nModule 7 : Plan d’action et mise en œuvre opérationnelle\n\n--- NIVEAU ---\nTous niveaux\n\n--- PUBLIC ---\nChefs de projet, responsables d’équipe, managers commerciaux, responsables marketing, data analysts et futurs data managers.\n\n--- MÉTHODES ---\nExposés interactifs, ateliers pratiques, études de cas, démonstrations techniques, simulations et discussions collectives.\n\n--- SUPPORTS ---\nOutils Big Data (Hadoop, Spark, SQL/NoSQL), logiciels BI, tableurs Excel, schémas techniques, supports PDF et slides.\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
